// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.sketch;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.List;

import org.junit.jupiter.api.Test;

class JoinCostVectorComparatorTest {

	private static final Candidate A = new Candidate("A", JoinCostVector.of(100.0d, 50.0d, 50.0d, 0.0d, 0.0d));
	private static final Candidate B = new Candidate("B", JoinCostVector.of(109.0d, 20.0d, 20.0d, 0.0d, 0.0d));
	private static final Candidate C = new Candidate("C", JoinCostVector.of(140.0d, 8.0d, 8.0d, 0.0d, 0.0d));

	@Test
	void comparatorIsTransitiveForReportedParetoCycle() {
		List<Candidate> candidates = List.of(A, B, C);

		for (Candidate left : candidates) {
			for (Candidate middle : candidates) {
				for (Candidate right : candidates) {
					if (left.vector().compareTo(middle.vector()) < 0
							&& middle.vector().compareTo(right.vector()) < 0) {
						assertTrue(left.vector().compareTo(right.vector()) < 0,
								() -> left.name() + " < " + middle.name() + " < " + right.name()
										+ " must imply " + left.name() + " < " + right.name());
					}
				}
			}
		}
	}

	@Test
	void frontierBestIsStableAcrossReportedCycleInsertionOrders() {
		List<List<Candidate>> insertionOrders = List.of(
				List.of(A, B, C),
				List.of(A, C, B),
				List.of(B, A, C),
				List.of(B, C, A),
				List.of(C, A, B),
				List.of(C, B, A));

		for (List<Candidate> insertionOrder : insertionOrders) {
			assertEquals("A", bestName(insertionOrder), () -> "Insertion order " + insertionOrder);
		}
	}

	private static String bestName(List<Candidate> insertionOrder) {
		ParetoFrontier<String> frontier = new ParetoFrontier<>(8);
		for (Candidate candidate : insertionOrder) {
			assertTrue(frontier.add(candidate.name(), candidate.vector()), () -> "Expected " + candidate + " accepted");
		}
		return frontier.best().value();
	}

	private record Candidate(String name, JoinCostVector vector) {

		@Override
		public String toString() {
			return name;
		}
	}
}
